'use client';

import { forwardRef } from 'react';
import { useComponentConfig } from '../config-provider/context';
import TextareaUI from './TextareaUI';
import type { TextareaProps } from './types';

const Textarea = forwardRef<HTMLTextAreaElement, TextareaProps>((props, ref) => {
  const config = useComponentConfig('textarea');

  const mergedProps = {
    ...config,
    ...props
  };

  return (
    <TextareaUI
      {...mergedProps}
      ref={ref}
    />
  );
});

Textarea.displayName = 'Textarea';

export default Textarea;

import { forwardRef } from 'react';
import { cn } from '@/lib/utils';
import { textareaVariants } from './textarea-variants';
import type { TextareaContentProps } from './types';

const TextareaContent = forwardRef<HTMLTextAreaElement, TextareaContentProps>((props, ref) => {
  const { className, size, ...rest } = props;

  const { content } = textareaVariants({ size });

  const mergedCls = cn(content(), className);

  return (
    <textarea
      className={mergedCls}
      data-size={size}
      data-slot="textarea"
      ref={ref}
      {...rest}
    />
  );
});

TextareaContent.displayName = 'TextareaContent';

export default TextareaContent;

import { cn } from '@/lib/utils';
import { textareaVariants } from './textarea-variants';
import type { TextareaCountProps } from './types';

const TextareaCount = (props: TextareaCountProps) => {
  const { children, className, countGraphemes, maxLength, size, value, ...rest } = props;

  const { count } = textareaVariants({ size });

  const mergedCls = cn(count(), className);

  const getCount = () => {
    if (!value) {
      return 0;
    }

    return countGraphemes?.(value) || String(value).length;
  };

  const countWithMaxLength = () => {
    const _count = getCount();
    if (maxLength) {
      return `${_count} / ${maxLength}`;
    }

    return String(_count);
  };

  const text = countWithMaxLength();

  return (
    <div
      {...rest}
      className={mergedCls}
      data-size={size}
      data-slot="textarea-count"
    >
      {children?.(text) || text}
    </div>
  );
};

export default TextareaCount;

import { cn } from '@/lib/utils';
import { textareaVariants } from './textarea-variants';
import type { TextareaRootProps } from './types';

const TextareaRoot = (props: TextareaRootProps) => {
  const { className, size, ...rest } = props;

  const { root } = textareaVariants({ size });

  const mergedCls = cn(root(), className);

  return (
    <div
      {...rest}
      className={mergedCls}
      data-size={size}
      data-slot="textarea-root"
    />
  );
};

export default TextareaRoot;

'use client';

import { type ChangeEvent, forwardRef } from 'react';
import { useControllableState } from '@radix-ui/react-use-controllable-state';
import TextareaContent from './TextareaContent';
import TextareaCount from './TextareaCount';
import TextareaRoot from './TextareaRoot';
import type { TextareaProps } from './types';

const TextareaUI = forwardRef<HTMLTextAreaElement, TextareaProps>((props, ref) => {
  const {
    classNames,
    countGraphemes,
    countRender,
    defaultValue,
    maxLength,
    onChange,
    onTextChange,
    showCount,
    size,
    value,
    ...rest
  } = props;

  const [_value, setValue] = useControllableState({
    caller: 'textarea',
    defaultProp: defaultValue,
    onChange: onTextChange,
    prop: value
  });

  function handleChange(e: ChangeEvent<HTMLTextAreaElement>) {
    setValue(e.target.value);
    onChange?.(e);
  }

  return (
    <TextareaRoot
      className={classNames?.root}
      size={size}
    >
      <TextareaContent
        className={classNames?.content}
        maxLength={maxLength}
        ref={ref}
        size={size}
        value={_value}
        onChange={handleChange}
        {...rest}
      />

      {showCount
        ? (
          <TextareaCount
            className={classNames?.count}
            countGraphemes={countGraphemes}
            maxLength={maxLength}
            size={size}
            value={_value}
          >
            {countRender}
          </TextareaCount>
        )
        : null}
    </TextareaRoot>
  );
});

TextareaUI.displayName = 'TextareaUI';

export default TextareaUI;

export { default as Textarea } from './Textarea';

export { default as TextareaContent } from './TextareaContent';
export { default as TextareaCount } from './TextareaCount';
export { default as TextareaRoot } from './TextareaRoot';

export * from './types';

import { tv } from 'tailwind-variants';

export const textareaVariants = tv({
  defaultVariants: {
    resize: 'vertical',
    size: 'md'
  },
  slots: {
    content: [
      `flex w-full rounded-md border border-solid border-input bg-background`,
      `focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:ring-offset-background focus-visible:ring-primary`,
      `disabled:cursor-not-allowed disabled:opacity-50`
    ],
    count: 'absolute z-2 leading-none text-muted-foreground',
    root: 'relative'
  },
  variants: {
    size: {
      '2xl': {
        content: 'min-h-12 px-4 py-2 text-xl',
        count: 'text-xl right-4 bottom-3.5'
      },
      'lg': {
        content: 'min-h-9 px-2.5 py-1 text-base',
        count: 'text-base right-3 bottom-2.5'
      },
      'md': {
        content: 'min-h-8 px-2 py-1 text-sm',
        count: 'text-sm right-2.5 bottom-2'
      },
      'sm': {
        content: 'min-h-7 px-1.75 py-1 text-xs',
        count: 'text-xs right-2 bottom-1.75'
      },
      'xl': {
        content: 'min-h-10 px-3 py-1 text-lg',
        count: 'text-lg right-3.5 bottom-3'
      },
      'xs': {
        content: 'min-h-6 px-1.5 py-1 text-2xs',
        count: 'text-2xs right-1.75 bottom-1.5'
      }
    }
  }
});

export type TextareaSlots = keyof typeof textareaVariants.slots;

import type { ReactNode } from 'react';
import type { HTMLComponentProps, ClassValue } from '@/types/shared';
import type { TextareaSlots } from './textarea-variants';

/**
 * Props for the textarea content element.
 * Represents the actual textarea HTML element.
 *
 * @example
 * ```tsx
 * const props: TextareaContentProps = {
 *   placeholder: 'Enter text...',
 *   maxLength: 500,
 *   value: 'Some text'
 * }
 * ```
 */
export interface TextareaContentProps extends HTMLComponentProps<'textarea'> {}

/**
 * Class names for different slots in the textarea component.
 * Allows customizing styles for specific parts (root, content, count, etc.).
 *
 * @example
 * ```tsx
 * const classNames: TextareaClassNames = {
 *   root: 'custom-root',
 *   content: 'custom-textarea',
 *   count: 'custom-count'
 * }
 * ```
 */
export type TextareaClassNames = Partial<Record<TextareaSlots, ClassValue>>;

/**
 * Props for the character count display component.
 * Manages the character or grapheme counting functionality.
 *
 * @example
 * ```tsx
 * const countProps: TextareaCountProps = {
 *   value: 'text',
 *   maxLength: 100,
 *   children: (count) => `${count}/100`,
 *   countGraphemes: (input) => input.length
 * }
 * ```
 */
export interface TextareaCountProps
  extends Omit<HTMLComponentProps<'div'>, 'children'>,
  Pick<TextareaContentProps, 'maxLength' | 'value'> {
  /**
   * Render function to display the character count.
   * Receives the formatted count string as a parameter.
   */
  children?: (count: string) => ReactNode;
  /**
   * Custom function to count characters.
   * Useful for counting graphemes instead of Unicode code units.
   * Receives the textarea value and returns the count.
   *
   * @param input - The textarea input value
   * @returns The count of characters/graphemes
   */
  countGraphemes?: (input: TextareaContentProps['value']) => number;
}

/**
 * Props for the textarea root/wrapper component.
 * The container element that wraps the textarea and count display.
 */
export interface TextareaRootProps extends HTMLComponentProps<'div'> {}

/**
 * Props for the Textarea component.
 * Combines textarea content, counting functionality, and styling options.
 *
 * @example
 * ```tsx
 * <Textarea
 *   placeholder="Enter your message..."
 *   maxLength={500}
 *   showCount={true}
 *   countRender={(count) => `${count}/500`}
 *   onTextChange={(value) => console.log(value)}
 *   classNames={{ count: 'text-gray-500' }}
 * />
 * ```
 */
export interface TextareaProps extends TextareaContentProps, Pick<TextareaCountProps, 'countGraphemes'> {
  /**
   * Class names for customizing different slots of the textarea component.
   */
  classNames?: TextareaClassNames;
  /**
   * Render function to display the character count.
   * Called with the formatted count string.
   * Only displayed when `showCount` is true.
   */
  countRender?: (count: string) => ReactNode;
  /**
   * Callback fired whenever the textarea value changes.
   * Receives the new value as a parameter.
   */
  onTextChange?: (value: TextareaContentProps['value']) => void;
  /**
   * Whether to display the character count.
   * When true, the count display is rendered below or near the textarea.
   */
  showCount?: boolean;
}
